from collections import Counter

class Solution(object):
    def minAnagramLength(self, s):
        n = len(s)
        total_freq = Counter(s)

        # Try each divisor of n as candidate length
        for length in range(1, n + 1):
            if n % length != 0:
                continue
            # Check if s is a concatenation of n//length anagrams of length
            # Each chunk must have the same character multiset
            # The multiset of any chunk must divide evenly into total_freq
            reps = n // length
            chunk_freq = Counter(s[:length])
            # Verify chunk_freq * reps == total_freq
            valid = True
            for c, cnt in chunk_freq.items():
                if total_freq[c] != cnt * reps:
                    valid = False
                    break
            if valid and len(chunk_freq) == len(total_freq):
                # Also verify all chunks are anagrams of the first chunk
                for i in range(0, n, length):
                    if Counter(s[i:i+length]) != chunk_freq:
                        valid = False
                        break
            else:
                valid = False
            if valid:
                return length
        return n
